function transform (message, context) {
  const contextUser = context.get('__user');
  const testPersonId = context.get('testPersonId');

  const personId = contextUser?.id || testPersonId;

  // Preserve the inbound answer ({ answer: true|false }) for later segments
  const { payload: { answer } = {} } = message;
  context.set('answer', answer === true);
  context.set('personId', personId);

  return { payload: { personId } };
}

function transform (message, context) {
  const { payload, payload: { credentials } = {} } = message;

  const bannerCredential = (credentials || []).find(c => c.type === 'bannerId');
  const bannerId = bannerCredential && bannerCredential.value;

  if (!bannerId) {
    const msg = 'Unable to resolve Banner ID for the current user';
    context.set('__httpStatusCode', 404);
    context.set('__httpStatusMessage', {
      correlationId: context['__runId'],
      component: context['__pipelineName'] + ':Resolve bannerId',
      error: '404',
      message: msg
    });
    throw new Error(msg);
  }

  context.set('bannerId', bannerId);

  return { ...message, payload: { ...payload, bannerId } };
}

function transform (message, context) {
  const awards = Array.isArray(message.payload) ? message.payload : [];
  const fundCodes = String(context.get('texasGrantFundCodes') || '')
    .split(',')
    .map(s => s.trim().toUpperCase())
    .filter(Boolean);

  const eligible = awards.some(a => a && fundCodes.includes(String(a.fundCode || '').toUpperCase()));

  if (!eligible) {
    const msg = 'Student is not awarded a Texas grant and may not submit this attestation';
    context.set('__httpStatusCode', 403);
    context.set('__httpStatusMessage', {
      correlationId: context['__runId'],
      component: context['__pipelineName'] + ':Check eligibility',
      error: '403',
      message: msg
    });
    throw new Error(msg);
  }

  return { payload: {} };
}

function transform (message, context) {
  const answer = context.get('answer') === true;
  const trstCode = answer ? context.get('trstCodeYes') : context.get('trstCodeNo');

  // RRRAREQ_STAT_DATE - today, formatted yyyy-mm-dd
  const now = new Date();
  const statDate = now.toISOString().slice(0, 10);

  const postBody = {
    keyblckId: context.get('bannerId'),
    keyblckAidyCode: context.get('aidYear'),
    treqCode: context.get('attestationTreqCode'),
    trstCode: trstCode,
    statDate: statDate
  };

  return { payload: postBody };
}
